import DashboardLayout from "../../components/layout/DashboardLayout";
import { useEffect, useState } from "react";
import { getUsers } from "../../api/adminApi";

export default function AdminDashboard() {
  const [stats, setStats] = useState({ total: 0, active: 0, blocked: 0 });

  useEffect(() => {
    loadStats();
  }, []);

  const loadStats = async () => {
    const data = await getUsers();
    const users = data.content || [];

    setStats({
      total: users.length,
      active: users.filter(u => u.status === "Активен").length,
      blocked: users.filter(u => u.status === "Заблокирован").length
    });
  };

  return (
    <DashboardLayout>
      <div className="p-6">
        <h1 className="text-3xl font-bold mb-6">Админ панель</h1>

        <div className="grid grid-cols-3 gap-6">

          <div className="p-6 rounded-2xl bg-gradient-to-r from-blue-500 to-indigo-500 text-white shadow-xl">
            <h3>Всего пользователей</h3>
            <p className="text-3xl font-bold">{stats.total}</p>
          </div>

          <div className="p-6 rounded-2xl bg-gradient-to-r from-green-400 to-green-600 text-white shadow-xl">
            <h3>Активные</h3>
            <p className="text-3xl font-bold">{stats.active}</p>
          </div>

          <div className="p-6 rounded-2xl bg-gradient-to-r from-red-400 to-red-600 text-white shadow-xl">
            <h3>Заблокированные</h3>
            <p className="text-3xl font-bold">{stats.blocked}</p>
          </div>

        </div>

        {/* cool visual element */}
        <div className="mt-10 p-6 bg-white rounded-2xl shadow-xl">
          <h3 className="text-xl mb-4">Активность системы</h3>
          <div className="h-40 flex items-end gap-2">
            {[20,40,60,30,80,50].map((h,i)=>(
              <div key={i} className="flex-1 bg-gradient-to-t from-indigo-500 to-purple-500 rounded" style={{height:h+"%"}}></div>
            ))}
          </div>
        </div>

      </div>
    </DashboardLayout>
  );
}
